/*Table structure for table `customers` */

DROP TABLE IF EXISTS `customers`;

CREATE TABLE `customers` (
  `customerid` int(11) NOT NULL AUTO_INCREMENT,
  `customername` varchar(50) DEFAULT NULL,
  `tradingname` varchar(50) DEFAULT NULL,
  `physicaladdress` varchar(50) DEFAULT NULL,
  `postaladdress` varchar(50) DEFAULT NULL,
  `mobile` varchar(50) DEFAULT NULL,
  `email` varchar(50) DEFAULT NULL,
  `creditlimit` decimal(10,0) DEFAULT NULL,
  `creditterm` int(11) DEFAULT NULL,
  `dateadded` datetime DEFAULT NULL,
  `addedby` decimal(10,0) DEFAULT NULL,
  `deleted` tinyint(1) DEFAULT 0,
  `lastdatemodified` datetime DEFAULT NULL,
  `lastmodifiedby` decimal(10,0) DEFAULT NULL,
  `catid` int(11) DEFAULT NULL,
  `posid` int(11) DEFAULT NULL,
  `onetimecustomer` tinyint(1) DEFAULT NULL,
  `pinno` varchar(50) DEFAULT NULL,
  `idno` varchar(50) DEFAULT NULL,
  `subzoneid` int(11) DEFAULT NULL,
  `town` varchar(50) DEFAULT '',
  `postalcode` varchar(50) DEFAULT '',
  PRIMARY KEY (`customerid`),
  KEY `catid` (`catid`),
  KEY `posid` (`posid`),
  CONSTRAINT `customers_ibfk_1` FOREIGN KEY (`catid`) REFERENCES `customercategories` (`id`),
  CONSTRAINT `customers_ibfk_2` FOREIGN KEY (`posid`) REFERENCES `pointsofsale` (`id`)
