/*Table structure for table `customersuspenseaccount` */

DROP TABLE IF EXISTS `customersuspenseaccount`;

CREATE TABLE `customersuspenseaccount` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `customerid` int(11) DEFAULT NULL,
  `transactiondate` datetime DEFAULT NULL,
  `referenceno` varchar(50) DEFAULT NULL,
  `debit` decimal(10,0) DEFAULT NULL,
  `credit` int(11) DEFAULT NULL,
  `addedby` int(11) DEFAULT NULL,
  `narration` varchar(500) DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `customerid` (`customerid`),
  KEY `addedby` (`addedby`),
  CONSTRAINT `customersuspenseaccount_ibfk_1` FOREIGN KEY (`customerid`) REFERENCES `customers` (`customerid`),
  CONSTRAINT `customersuspenseaccount_ibfk_2` FOREIGN KEY (`addedby`) REFERENCES `user` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=21 DEFAULT CHARSET=latin1;

