) ENGINE=InnoDB DEFAULT CHARSET=latin1;

/*Data for the table `defaultterms` */

insert  into `defaultterms`(`purchaseorder`,`quotation`) values ('1) Items are paid on delivery\r\n2) Only items meeting specification will be accepted\r\n3) Invoices are due on demand\r\n4) Include a copy of the quotation on order\r\n5) This quotation is valid for 7 days','1) Above prices are subject to 16% VAT\r\n2) Payment terms: Cash Payment\r\n3) Quotation validity 14 Days\r\n4) Size tolerance :+/- 3mm\r\n5) Quality tolerance: +/- 10%\r\n6) Closure: Stitching\r\n7) Lead time One week\r\n\r\nIMPORTANT: issuance of LPO  for the above cartons will be considered as an acceptance  of this quotation and  terms and conditions stated herein\r\n\r\nAwaiting for your favorable response and assuring you of the best quality and efficient service');

