/*Table structure for table `goodsreceived` */

DROP TABLE IF EXISTS `goodsreceived`;

CREATE TABLE `goodsreceived` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `warehouseid` int(11) DEFAULT NULL,
  `grnno` varchar(50) DEFAULT NULL,
  `datereceived` datetime DEFAULT NULL,
  `supplierid` int(11) DEFAULT NULL,
  `deliverynono` varchar(50) DEFAULT NULL,
  `receivedby` int(11) DEFAULT NULL,
  `status` varchar(50) DEFAULT NULL,
  `lastmodifiedon` datetime DEFAULT NULL,
  `lastmodifiedby` int(11) DEFAULT NULL,
  `invoiced` tinyint(1) DEFAULT 0,
  `invoiceno` varchar(50) DEFAULT NULL,
  `inspectedby` int(11) DEFAULT NULL,
  `narration` varchar(1000) DEFAULT NULL,
  `deliveredby` varchar(100) DEFAULT NULL,
  KEY `id` (`id`),
  KEY `warehouseid` (`warehouseid`),
  KEY `supplierid` (`supplierid`),
  KEY `receivedby` (`receivedby`),
  KEY `lastmodifiedby` (`lastmodifiedby`),
  CONSTRAINT `goodsreceived_ibfk_1` FOREIGN KEY (`warehouseid`) REFERENCES `warehouses` (`id`),
  CONSTRAINT `goodsreceived_ibfk_2` FOREIGN KEY (`supplierid`) REFERENCES `suppliers` (`supplierid`),
  CONSTRAINT `goodsreceived_ibfk_3` FOREIGN KEY (`receivedby`) REFERENCES `user` (`id`),
  CONSTRAINT `goodsreceived_ibfk_4` FOREIGN KEY (`lastmodifiedby`) REFERENCES `user` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=50 DEFAULT CHARSET=latin1;

/*Data for the table `goodsreceived` */

