/*Table structure for table `materialissue` */

DROP TABLE IF EXISTS `materialissue`;

CREATE TABLE `materialissue` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `warehouseid` int(11) DEFAULT NULL,
  `sinno` varchar(50) DEFAULT NULL,
  `dateissued` datetime DEFAULT NULL,
  `issuedby` int(11) DEFAULT NULL,
  `issuedto` int(11) DEFAULT NULL,
  `materialrequestid` int(11) DEFAULT NULL,
  `narration` varchar(50) DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `issuedby` (`issuedby`),
  KEY `issuedto` (`issuedto`),
  KEY `materialrequestid` (`materialrequestid`),
  KEY `warehouseid` (`warehouseid`),
  CONSTRAINT `materialissue_ibfk_1` FOREIGN KEY (`issuedby`) REFERENCES `user` (`id`),
  CONSTRAINT `materialissue_ibfk_2` FOREIGN KEY (`issuedto`) REFERENCES `user` (`id`),
  CONSTRAINT `materialissue_ibfk_3` FOREIGN KEY (`materialrequestid`) REFERENCES `materialrequest` (`id`),
  CONSTRAINT `materialissue_ibfk_4` FOREIGN KEY (`warehouseid`) REFERENCES `warehouses` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=11 DEFAULT CHARSET=latin1;

/*Data for the table `materialissue` */

