/*Table structure for table `materialissuedetails` */

DROP TABLE IF EXISTS `materialissuedetails`;

CREATE TABLE `materialissuedetails` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `materialissueid` int(11) DEFAULT NULL,
  `quantity` int(11) DEFAULT NULL,
  `materialreceiptid` int(11) DEFAULT NULL,
  `materialid` int(11) DEFAULT NULL,
  `serialno` varchar(100) DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `materialissueid` (`materialissueid`),
  KEY `materialreceiptid` (`materialreceiptid`),
  KEY `materialid` (`materialid`),
  CONSTRAINT `materialissuedetails_ibfk_1` FOREIGN KEY (`materialissueid`) REFERENCES `materialissue` (`id`),
  CONSTRAINT `materialissuedetails_ibfk_3` FOREIGN KEY (`materialid`) REFERENCES `materialdetails` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=33 DEFAULT CHARSET=latin1;

