  CONSTRAINT `materialreceiptdetails_ibfk_3` FOREIGN KEY (`poid`) REFERENCES `purchaseorders` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=222 DEFAULT CHARSET=latin1;

