CREATE TABLE `materialreceipts` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `warehouseid` int(11) DEFAULT NULL,
  `grnno` varchar(50) DEFAULT NULL,
  `source` varchar(50) DEFAULT NULL,
  `supplierid` int(11) DEFAULT NULL,
  `customerid` int(11) DEFAULT NULL,
  `datereceived` datetime DEFAULT NULL,
  `receivedby` int(11) DEFAULT NULL,
  `inspectedby` int(11) DEFAULT NULL,
  `materialusecaseid` int(11) DEFAULT NULL,
  `deliverynoteno` varchar(50) DEFAULT NULL,
  `narration` varchar(2500) DEFAULT NULL,
  `projectid` int(11) DEFAULT NULL,
  `deliveredby` varchar(50) DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `receivedby` (`receivedby`),
  KEY `inspectedby` (`inspectedby`),
  KEY `materialusecaseid` (`materialusecaseid`),
  KEY `projectid` (`projectid`),
  KEY `supplierid` (`supplierid`),
  KEY `customerid` (`customerid`),
  KEY `warehouseid` (`warehouseid`),
  CONSTRAINT `materialreceipts_ibfk_1` FOREIGN KEY (`receivedby`) REFERENCES `user` (`id`),
  CONSTRAINT `materialreceipts_ibfk_2` FOREIGN KEY (`inspectedby`) REFERENCES `user` (`id`),
  CONSTRAINT `materialreceipts_ibfk_3` FOREIGN KEY (`materialusecaseid`) REFERENCES `materialusecases` (`id`),
  CONSTRAINT `materialreceipts_ibfk_4` FOREIGN KEY (`projectid`) REFERENCES `projects` (`id`),
  CONSTRAINT `materialreceipts_ibfk_5` FOREIGN KEY (`supplierid`) REFERENCES `suppliers` (`supplierid`),
  CONSTRAINT `materialreceipts_ibfk_6` FOREIGN KEY (`customerid`) REFERENCES `nmc` (`id`),
  CONSTRAINT `materialreceipts_ibfk_7` FOREIGN KEY (`warehouseid`) REFERENCES `warehouses` (`id`),
  CONSTRAINT `allowmaterialsource` CHECK (`source` in ('customer','supplier'))
) ENGINE=InnoDB AUTO_INCREMENT=30 DEFAULT CHARSET=latin1;

