/*Table structure for table `materialrequest` */

DROP TABLE IF EXISTS `materialrequest`;

CREATE TABLE `materialrequest` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `requisitionno` varchar(50) DEFAULT NULL,
  `materialusecase` int(11) DEFAULT NULL,
  `purchaserequisition` tinyint(1) DEFAULT NULL,
  `reference` varchar(50) DEFAULT NULL,
  `requestdate` datetime DEFAULT NULL,
  `requestedby` int(11) DEFAULT NULL,
  `narration` varchar(5000) DEFAULT NULL,
  `addedby` int(11) DEFAULT NULL,
  `scope` varchar(50) DEFAULT NULL,
  `supplierid` int(11) DEFAULT NULL,
  `activityid` int(11) DEFAULT NULL,
  `departmentid` int(11) DEFAULT NULL,
  `rejected` tinyint(1) DEFAULT 0,
  `rejectedlevelid` int(11) DEFAULT NULL,
  `rejectedreason` varchar(500) DEFAULT NULL,
  `rejectedby` int(11) DEFAULT NULL,
  `rejecteddate` datetime DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `materialusecase` (`materialusecase`),
  KEY `materialrequest_ibfk_3` (`addedby`),
  KEY `supplierid` (`supplierid`),
  KEY `activityid` (`activityid`),
  KEY `departmentid` (`departmentid`),
  KEY `requestedby` (`requestedby`),
  CONSTRAINT `materialrequest_ibfk_1` FOREIGN KEY (`materialusecase`) REFERENCES `materialusecases` (`id`),
  CONSTRAINT `materialrequest_ibfk_3` FOREIGN KEY (`addedby`) REFERENCES `user` (`id`),
  CONSTRAINT `materialrequest_ibfk_4` FOREIGN KEY (`supplierid`) REFERENCES `suppliers` (`supplierid`),
  CONSTRAINT `materialrequest_ibfk_5` FOREIGN KEY (`activityid`) REFERENCES `projectactivities` (`id`),
  CONSTRAINT `materialrequest_ibfk_6` FOREIGN KEY (`departmentid`) REFERENCES `departments` (`id`),
  CONSTRAINT `materialrequest_ibfk_7` FOREIGN KEY (`requestedby`) REFERENCES `user` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=38 DEFAULT CHARSET=latin1;

