/*Table structure for table `paymentvouchers` */

DROP TABLE IF EXISTS `paymentvouchers`;

CREATE TABLE `paymentvouchers` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `voucherno` varchar(50) DEFAULT NULL,
  `date` datetime DEFAULT NULL,
  `dateadded` datetime DEFAULT NULL,
  `addedby` int(11) DEFAULT NULL,
  `paymentmode` int(11) DEFAULT NULL,
  `pos` int(11) DEFAULT NULL,
  `supplier` int(11) DEFAULT NULL,
  `cashbookaccount` int(11) DEFAULT NULL,
  `referenceno` varchar(50) DEFAULT NULL,
  `status` varchar(50) DEFAULT NULL,
  `lastmodifiedby` int(11) DEFAULT NULL,
  `lastmodifieddate` datetime DEFAULT NULL,
  `reasoncancelled` varchar(500) DEFAULT NULL,
  `pettycashvoucher` tinyint(1) DEFAULT 0,
  PRIMARY KEY (`id`),
  KEY `addedby` (`addedby`),
  KEY `pos` (`pos`),
  KEY `paymentmode` (`paymentmode`),
  KEY `supplier` (`supplier`),
  KEY `lastmodifiedby` (`lastmodifiedby`),
  CONSTRAINT `paymentvouchers_ibfk_1` FOREIGN KEY (`addedby`) REFERENCES `user` (`id`),
  CONSTRAINT `paymentvouchers_ibfk_2` FOREIGN KEY (`pos`) REFERENCES `pointsofsale` (`id`),
