/*Table structure for table `possalesdetails` */

DROP TABLE IF EXISTS `possalesdetails`;

CREATE TABLE `possalesdetails` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `possaleid` int(11) DEFAULT NULL,
  `itemcode` int(50) DEFAULT NULL,
  `quantity` decimal(10,2) DEFAULT NULL,
  `unitprice` decimal(10,2) DEFAULT NULL,
  `discount` decimal(10,2) DEFAULT NULL,
  `serialno` varchar(100) DEFAULT NULL,
  `taxtypeid` int(11) DEFAULT NULL,
  `taxrate` decimal(18,2) DEFAULT NULL,
  `description` varchar(500) DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `possaleid` (`possaleid`),
  KEY `itemcode` (`itemcode`),
  CONSTRAINT `possalesdetails_ibfk_1` FOREIGN KEY (`possaleid`) REFERENCES `possales` (`id`),
  CONSTRAINT `possalesdetails_ibfk_2` FOREIGN KEY (`itemcode`) REFERENCES `products` (`productid`)
) ENGINE=InnoDB AUTO_INCREMENT=425 DEFAULT CHARSET=latin1;

