  `supplierid` int(11) DEFAULT NULL,
  `departmentid` int(11) DEFAULT NULL,
  `expecteddate` datetime DEFAULT NULL,
  `status` varchar(50) DEFAULT 'Pending',
  `terms` varchar(1000) DEFAULT NULL,
  `addedby` int(11) DEFAULT NULL,
  `lastmodifiedon` datetime DEFAULT NULL,
  `lastmodifiedby` int(11) DEFAULT NULL,
  `reasoncancelled` varchar(100) DEFAULT NULL,
  `category` varchar(50) DEFAULT NULL,
  `currencyid` int(11) DEFAULT NULL,
  `exchangerate` decimal(18,2) DEFAULT NULL,
  `rejected` tinyint(1) DEFAULT 0,
  `rejecteddate` datetime DEFAULT NULL,
  `rejectedby` int(11) DEFAULT NULL,
  `rejectedreason` varchar(1000) DEFAULT NULL,
  `rejectedlevelid` int(11) DEFAULT NULL,
  `taxid` int(11) DEFAULT NULL,
  `taxrate` decimal(18,2) DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `id` (`id`),
  KEY `addedby` (`addedby`),
  KEY `lastmodifiedby` (`lastmodifiedby`),
  KEY `departmentid` (`departmentid`),
  KEY `currencyid` (`currencyid`),
  KEY `rejectedby` (`rejectedby`),
  KEY `rejectedlevelid` (`rejectedlevelid`),
  KEY `taxid` (`taxid`),
  CONSTRAINT `purchaseorders_ibfk_1` FOREIGN KEY (`addedby`) REFERENCES `user` (`id`),
  CONSTRAINT `purchaseorders_ibfk_2` FOREIGN KEY (`lastmodifiedby`) REFERENCES `user` (`id`),
  CONSTRAINT `purchaseorders_ibfk_3` FOREIGN KEY (`departmentid`) REFERENCES `departments` (`id`),
  CONSTRAINT `purchaseorders_ibfk_4` FOREIGN KEY (`currencyid`) REFERENCES `currencies` (`id`),
  CONSTRAINT `purchaseorders_ibfk_5` FOREIGN KEY (`rejectedby`) REFERENCES `user` (`id`),
  CONSTRAINT `purchaseorders_ibfk_6` FOREIGN KEY (`rejectedlevelid`) REFERENCES `purchaseorderapprovallevels` (`id`),
  CONSTRAINT `purchaseorders_ibfk_7` FOREIGN KEY (`taxid`) REFERENCES `taxtypes` (`id`),
  CONSTRAINT `CONSTRAINT_1` CHECK (ucase(`category`) in ('PRODUCT','RAW MATERIAL'))
) ENGINE=InnoDB AUTO_INCREMENT=50 DEFAULT CHARSET=latin1;

