/*Table structure for table `supplierproducts` */

DROP TABLE IF EXISTS `supplierproducts`;

CREATE TABLE `supplierproducts` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `supplierid` int(11) DEFAULT NULL,
