  CONSTRAINT `supplierproducts_ibfk_4` FOREIGN KEY (`lastmodifiedby`) REFERENCES `user` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=11 DEFAULT CHARSET=latin1;

