/* Procedure structure for procedure `spgetstocksheet` */

/*!50003 DROP PROCEDURE IF EXISTS  `spgetstocksheet` */;

DELIMITER $$

/*!50003 CREATE DEFINER=`root`@`localhost` PROCEDURE `spgetstocksheet`($asat datetime)
BEGIN
	
	SET @asat=$asat;
	SET @cutoffdate=date_format(IFNULL((SELECT `stockcutoffdate` FROM `startingparameters`),NOW()),'%Y-%m-%d');
	SET @sql_dynamic=(SELECT GROUP_CONCAT(CONCAT('FORMAT(SUM(IF(storename=''',`posname`,''',itemtotal,0)),2) AS `',`posname`,'`')) FROM `vwstores`);
	SET @sql=CONCAT('SELECT `categoryname`,`itemcode`,`itemname`,',@sql_dynamic,',FORMAT(SUM(itemtotal),2) as `Total Quantity`, FORMAT(SUM(itemtotal)*`buyingprice`,2) as `Total Purchase`,FORMAT(SUM(itemtotal)*`sellingprice`,2) as `Total Selling`
		FROM (SELECT `categoryname`,`itemcode`,`itemname`,`buyingprice`,`sellingprice`,`storename`, SUM(units) as `itemtotal` FROM ','(SELECT `categoryname`,`itemcode`,`itemname`,`buyingprice`,`sellingprice`,w.`description` AS storename,
		-- sum goods received
		IFNULL((SELECT SUM(`quantity`) FROM `goodsreceiveddetails` gd, `goodsreceived` g WHERE g.`grnno`=gd.`grnno` AND gd.`itemcode`=p.`productid` 
			AND DATE_FORMAT(`datereceived`,''%Y-%m-%d'') BETWEEN ','''',@cutoffdate,'''',' AND ','''',@asat,'''',' AND g.`warehouseid`=w.`id`),0)+
		-- Add transfers in
		IFNULL((SELECT SUM(`quantity`) FROM `stocktransferdetails` sd, `stocktransfer` s WHERE s.`id`=sd.`transferid` AND sd.`itemcode`=p.`productid` 
			AND s.`destinationtype`=''warehouse'' AND s.`destinationid`=w.`id` AND DATE_FORMAT(`dateadded`,''%Y-%m-%d'') BETWEEN ','''',@cutoffdate,'''',' AND ','''',@asat,'''','),0)-
		-- Less Transfers out
		IFNULL((SELECT SUM(`quantity`) FROM `stocktransferdetails` sd, `stocktransfer` s WHERE s.`id`=sd.`transferid` AND sd.`itemcode`=p.`productid` 
			AND s.`sourcetype`=''warehouse'' AND s.`sourceid`=w.`id` AND DATE_FORMAT(`dateadded`,''%Y-%m-%d'')BETWEEN ','''',@cutoffdate,'''',' AND ','''',@asat,'''','),0) AS units
		FROM `categories` c, `products` p, `warehouses` w
		WHERE p.`categoryid`=c.`categoryid`
		
		UNION 
		
		SELECT `categoryname`,`itemcode`,`itemname`,`buyingprice`,`sellingprice`,w.`posname` AS storename,
		-- Add transfers in
		IFNULL((SELECT SUM(`quantity`) FROM `stocktransferdetails` sd, `stocktransfer` s WHERE s.`id`=sd.`transferid` AND sd.`itemcode`=p.`productid` 
			AND s.`destinationtype`=''pos'' AND s.`destinationid`=w.`id` AND DATE_FORMAT(`dateadded`,''%Y-%m-%d'') BETWEEN ','''',@cutoffdate,'''',' AND ','''',@asat,'''','),0)-
		-- Less Transfers out
		IFNULL((SELECT SUM(`quantity`) FROM `stocktransferdetails` sd, `stocktransfer` s WHERE s.`id`=sd.`transferid` AND sd.`itemcode`=p.`productid` 
			AND s.`sourcetype`=''pos'' AND s.`sourceid`=w.`id` AND DATE_FORMAT(`dateadded`,''%Y-%m-%d'') BETWEEN ','''',@cutoffdate,'''',' AND ','''',@asat,'''','),0)-
		-- Less Sales
		IFNULL((SELECT SUM(`quantity`) FROM `possalesdetails` pd, `possales` ps WHERE pd.`possaleid`=ps.`id` AND IFNULL(`deleted`,0)=0 AND `pointofsaleid`=w.id 
			AND pd.`itemcode`=p.`productid`  AND DATE_FORMAT(`receiptdate`,''%Y-%m-%d'') BETWEEN ','''',@cutoffdate,'''',' AND ','''',@asat,'''','),0) AS units
		FROM `categories` c, `products` p, `pointsofsale` w
		WHERE p.`categoryid`=c.`categoryid`
		ORDER BY `categoryname`,`itemname`) as tab1 
		GROUP BY `categoryname`,`itemcode`,`itemname`,`buyingprice`,`sellingprice`,`storename` )as tab2
		GROUP BY `categoryname`,`itemcode`,`itemname`,`buyingprice`,`sellingprice` HAVING SUM(itemtotal)>0');
	/*select @sql;*/
	PREPARE stmt FROM @sql;
	EXECUTE stmt;
	DEALLOCATE PREPARE stmt;
    END */$$
DELIMITER ;

/* Procedure structure for procedure `spgetstocktransferbalance` */

/*!50003 DROP PROCEDURE IF EXISTS  `spgetstocktransferbalance` */;

