DELIMITER $$

/*!50003 CREATE DEFINER=`root`@`localhost` PROCEDURE `spsavecustomerdiscountsettings`($id numeric,$customerid numeric,$productid numeric,$discount numeric,
	$percentage bit,$userid numeric,$expirydate datetime)
BEGIN
