DELIMITER $$

/*!50003 CREATE DEFINER=`root`@`localhost` PROCEDURE `spsavestockreconciledbalance`($refno varchar(50),$narration varchar(50),$userid int)
BEGIN
	start transaction;
		-- Insert reconcilliation header
		insert into `stockreconciledbalance`(`reconciliationdate`,`userid`,`narration`)
		values(now(),$userid,$narration);
		-- Get the Inserted Id
		set @id=(select max(id) from `stockreconciledbalance`);
		-- Insert the reconcilliation details
		insert into `stockreconciledbalancedetails` (`reconciliationid`,`itemid`,`quantity`,`unitprice`)
