/*!50003 CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_savefleetvehicle`(`$vehicleid` INT, `$regno` VARCHAR(50), `$bodytypeid` INT, `$fueltypeid` INT, `$enginerating` INT, `$userid` INT)
BEGIN
	if $vehicleid=0 then
