/*!50001 DROP TABLE IF EXISTS `vwcustomerreceipts` */;
/*!50001 DROP VIEW IF EXISTS `vwcustomerreceipts` */;

/*!50001 CREATE ALGORITHM=UNDEFINED DEFINER=`root`@`localhost` SQL SECURITY DEFINER VIEW `vwcustomerreceipts` AS (select `r`.`id` AS `id`,date_format(`r`.`receiptdate`,'%Y-%m-%d') AS `date`,`o`.`posname` AS `posname`,`c`.`customername` AS `customername`,`r`.`receiptno` AS `receiptno`,`r`.`modeofpayment` AS `paymentmodeid`,`p`.`description` AS `description`,`r`.`referenceno` AS `reference`,ifnull(`r`.`banked`,0) AS `banked`,sum(`rd`.`amount`) AS `amount`,concat(`u`.`firstname`,' ',`u`.`lastname`) AS `addedby` from (((((`customerreceipts` `r` join `customerreceiptdetails` `rd`) join `customers` `c`) join `paymentmethods` `p`) join `pointsofsale` `o`) join `user` `u`) where `r`.`id` = `rd`.`receiptid` and `r`.`customerid` = `c`.`customerid` and `c`.`posid` = `o`.`id` and `r`.`modeofpayment` = `p`.`id` and ifnull(`r`.`deleted`,0) = 0 and `r`.`addedby` = `u`.`id` group by `r`.`id`,`o`.`posname`,`c`.`customername`,`r`.`receiptno`,`r`.`modeofpayment`,`p`.`description`,`r`.`referenceno`,`r`.`banked`,concat(`u`.`firstname`,' ',`u`.`lastname`) order by date_format(`r`.`receiptdate`,'%Y-%m-%d')) */;

/*View structure for view vwcustomerstomerstatement */

/*!50001 DROP TABLE IF EXISTS `vwcustomerstomerstatement` */;
/*!50001 DROP VIEW IF EXISTS `vwcustomerstomerstatement` */;

/*!50001 CREATE ALGORITHM=UNDEFINED DEFINER=`root`@`localhost` SQL SECURITY DEFINER VIEW `vwcustomerstomerstatement` AS select `p`.`id` AS `id`,`c`.`customerid` AS `customerid`,`c`.`customername` AS `customername`,`c`.`physicaladdress` AS `physicaladdress`,`c`.`postaladdress` AS `postaladdress`,`c`.`mobile` AS `mobile`,`c`.`email` AS `email`,`p`.`receiptdate` AS `date`,'Invoice issued to customer' AS `narration`,`pm`.`reference` AS `reference`,`pm`.`amount` AS `invoiceamount`,0 AS `invoicepayment`,0 AS `order` from (((`customers` `c` join `possales` `p`) join `possalesdetails` `pd`) join `possalespayments` `pm`) where `c`.`customerid` = `p`.`customerid` and `p`.`id` = `pd`.`possaleid` and `pm`.`possaleid` = `p`.`id` and `pm`.`paymentmode` = 4 and date_format(`p`.`receiptdate`,'%Y-%m-%d') >= (select date_format(`startingparameters`.`cutoffdate`,'%Y-%m-%d') from `startingparameters`) group by `c`.`customerid`,`c`.`customername`,`c`.`physicaladdress`,`c`.`postaladdress`,`c`.`mobile`,`c`.`email`,`pm`.`reference`,`p`.`receiptdate` union select `cr`.`id` AS `id`,`c`.`customerid` AS `customerid`,`c`.`customername` AS `customername`,`c`.`physicaladdress` AS `physicaladdress`,`c`.`postaladdress` AS `postaladdress`,`c`.`mobile` AS `mobile`,`c`.`email` AS `email`,`cr`.`receiptdate` AS `date`,'Payment received. Thank You' AS `narration`,`cr`.`receiptno` AS `receiptno`,0 AS `invoiceamount`,sum(`cd`.`amount`) + ifnull((select sum(`customersuspenseaccount`.`credit`) from `customersuspenseaccount` where `customersuspenseaccount`.`referenceno` = `cr`.`receiptno`),0) AS `invoicepayment`,1 AS `order` from ((`customers` `c` join `customerreceipts` `cr`) join `customerreceiptdetails` `cd`) where `c`.`customerid` = `cr`.`customerid` and `cr`.`id` = `cd`.`receiptid` and date_format(`cr`.`receiptdate`,'%Y-%m-%d') >= (select date_format(`startingparameters`.`cutoffdate`,'%Y-%m-%d') from `startingparameters`) group by `cr`.`id`,`c`.`customerid`,`c`.`customername`,`c`.`physicaladdress`,`c`.`postaladdress`,`c`.`mobile`,`c`.`email`,`cr`.`receiptdate`,`cr`.`receiptno` order by `date`,`order` */;

