/*!50001 DROP TABLE IF EXISTS `vwpaymentvouchers` */;
/*!50001 DROP VIEW IF EXISTS `vwpaymentvouchers` */;

/*!50001 CREATE ALGORITHM=UNDEFINED DEFINER=`root`@`localhost` SQL SECURITY DEFINER VIEW `vwpaymentvouchers` AS (select `p`.`id` AS `voucherid`,ifnull(`p`.`pettycashvoucher`,0) AS `pettycashvoucher`,`p`.`voucherno` AS `voucherno`,date_format(`p`.`date`,'%Y-%m-%d') AS `voucherdate`,`p`.`paymentmode` AS `paymentmodeid`,`m`.`description` AS `paymentmodedescription`,`p`.`pos` AS `posid`,`o`.`posname` AS `posname`,`p`.`supplier` AS `supplierid`,`s`.`suppliername` AS `suppliername`,`pd`.`invoicenumber` AS `invoicenumber`,`p`.`cashbookaccount` AS `cashbookaccountid`,`a`.`accountcode` AS `accountcode`,`a`.`accountname` AS `accountname`,`p`.`referenceno` AS `referenceno`,`p`.`status` AS `status`,sum(`pd`.`quantity` * `pd`.`unitprice`) AS `vouchertotal`,`p`.`addedby` AS `userid`,concat(`u`.`firstname`,' ',`u`.`middlename`,' ',`u`.`lastname`) AS `username` from ((((((`paymentvouchers` `p` join `paymentvoucherdetails` `pd`) join `suppliers` `s`) join `paymentmethods` `m`) join `pointsofsale` `o`) join `glaccounts` `a`) join `user` `u`) where `p`.`id` = `pd`.`voucherid` and `p`.`supplier` = `s`.`supplierid` and `p`.`paymentmode` = `m`.`id` and `p`.`cashbookaccount` = `a`.`id` and `p`.`addedby` = `u`.`id` and `p`.`pos` = `o`.`id` group by `p`.`id`,`p`.`voucherno`,date_format(`p`.`date`,'%Y-%m-%d'),`p`.`paymentmode`,`m`.`description`,`p`.`pos`,`p`.`supplier`,`pd`.`invoicenumber`,`p`.`cashbookaccount`,`a`.`accountcode`,`a`.`accountname`,`p`.`referenceno`,`p`.`status`,`p`.`addedby`,concat(`u`.`firstname`,' ',`u`.`middlename`,' ',`u`.`lastname`)) */;

